module mux8to1 (
    input [7:0] data,  // 8 data inputs
    input [2:0] sel,   // 3-bit select input
    output reg obf_y       // output
);
    always @(*) begin
        case (sel)
            3'b000: obf_y = data[0];
            3'b001: obf_y = data[1];
            3'b010: obf_y = data[2];
            3'b011: obf_y = data[3];
            3'b100: obf_y = data[4];
            3'b101: obf_y = data[5];
            3'b110: obf_y = data[6];
            3'b111: obf_y = data[7];
            default: obf_y = 1'b0; // default case
        endcase
    end
endmodule
